Dataflow hash-aggregates in one pass; MapReduce pays for partitioned spill files plus per-reducer sort even on a single machine — usually slower here when cardinality fits in RAM.

```python
#!/usr/bin/env python3
"""ch11_aggregate.py — complete reference"""
from pathlib import Path
from collections import Counter
import time

DOCS = Path("docs")
MR_DIR = Path("mr_out")

def map_partition(text: str, n_reducers: int):
    for word in text.split():
        yield hash(word) % n_reducers, word, 1

def run_mapreduce(n_reducers: int = 4) -> Counter:
    if MR_DIR.exists():
        for p in MR_DIR.iterdir():
            p.unlink()
    else:
        MR_DIR.mkdir()

    handles = {
        r: open(MR_DIR / f"map-r{r}.tsv", "w", encoding="utf-8")
        for r in range(n_reducers)
    }
    try:
        for path in sorted(DOCS.glob("part-*.txt")):
            text = path.read_text(encoding="utf-8")
            for rid, word, one in map_partition(text, n_reducers):
                handles[rid].write(f"{word}\t{one}\n")
    finally:
        for fh in handles.values():
            fh.close()

    out = Counter()
    for rid in range(n_reducers):
        spill = MR_DIR / f"map-r{rid}.tsv"
        lines = spill.read_text(encoding="utf-8").splitlines()
        lines.sort()
        (MR_DIR / f"sorted-r{rid}.tsv").write_text(
            "\n".join(lines) + ("\n" if lines else ""), encoding="utf-8"
        )
        current = None
        total = 0
        for line in lines:
            word, one = line.split("\t")
            if word != current:
                if current is not None:
                    out[current] += total
                current, total = word, 0
            total += int(one)
        if current is not None:
            out[current] += total
    return out

def run_dataflow() -> Counter:
    counts = Counter()
    for path in sorted(DOCS.glob("part-*.txt")):
        counts.update(path.read_text(encoding="utf-8").split())
    return counts

if __name__ == "__main__":
    t0 = time.perf_counter()
    mr = run_mapreduce()
    t1 = time.perf_counter()
    df = run_dataflow()
    t2 = time.perf_counter()
    assert mr == df
    print(f"mapreduce_s={t1-t0:.3f} dataflow_s={t2-t1:.3f} words={len(mr)}")
    print("mr files", len(list(MR_DIR.iterdir())))
```

Write-up: The MapReduce path always partitions, writes spills, and sorts before reduce. The dataflow path fuses flatmap + aggregate in memory with no stage barrier and no shuffle files — the same reason Spark/Flink beat classic MR on many jobs when the working set fits.
